package ssg
package js
package compress

import CompressTestHelper.{ AllOff, assertCompresses }

final class CompressIssue1248Suite extends munit.FunSuite {

  override val munitTimeout = scala.concurrent.duration.Duration(120, "s")

  // =========================================================================
  // brackets_with_const
  // =========================================================================
  test("brackets_with_const") {
    assertCompresses(
      input = """if (a) {
            var b;
            var c;
            const d = d();
            const e = e();
        }""".stripMargin.trim,
      expected = "if(a){var b;var c;const d=d();const e=e()}",
      options = AllOff
    )
  }

  // =========================================================================
  // brackets_with_const_defaults
  // =========================================================================
  test("brackets_with_const_defaults".fail) {
    assertCompresses(
      input = """if (a) {
            var b;
            var c;
            const d = d();
            const e = e();
        }""".stripMargin.trim,
      expected = "if(a){var b,c;const d=d(),e=e()}",
      options = AllOff
    )
  }

  // =========================================================================
  // brackets_with_const_let_mix_0
  // =========================================================================
  test("brackets_with_const_let_mix_0".fail) {
    assertCompresses(
      input = """if (a) {
            var b;
            var c;
            const d = d();
            let e = e();
        }""".stripMargin.trim,
      expected = "if(a){var b,c;const d=d();let e=e()}",
      options = AllOff
    )
  }

  // =========================================================================
  // brackets_with_const_let_mix_1
  // =========================================================================
  test("brackets_with_const_let_mix_1".fail) {
    assertCompresses(
      input = """if (a) {
            let b = b();
            var c;
